import React from "react";
import { motion } from "framer-motion";
import { Apple } from "lucide-react";

export function NavHeader() {
  return (
    <motion.header
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      className="relative z-50 w-full px-12 py-8 flex items-center justify-between"
    >
      <div className="flex items-center gap-3">
        <div className="p-2.5 bg-primary rounded-2xl shadow-lg shadow-primary/20">
          <Apple className="w-7 h-7 text-white" />
        </div>
        <span className="text-3xl font-black text-gray-900 tracking-tighter">
          Foodies
        </span>
      </div>

      <nav className="hidden md:flex items-center gap-12">
        <a href="#about" className="text-sm font-bold text-gray-400 hover:text-primary transition-colors">About</a>
        <a href="#impact" className="text-sm font-bold text-gray-400 hover:text-primary transition-colors">Impact</a>
        <a href="#contact" className="text-sm font-bold text-gray-400 hover:text-primary transition-colors">Contact</a>
      </nav>

      <div>
        <button className="px-8 py-3 text-sm font-bold text-gray-600 hover:text-gray-900 border-2 border-gray-100 rounded-2xl hover:bg-gray-50 transition-all">
          Contact Support
        </button>
      </div>
    </motion.header>
  );
}
